import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import './App.css';
import WelcomeScreen from './components/WelcomeScreen';
import SafeWordSetup from './components/SafeWordSetup';
import ChatInterface from './components/ChatInterface';
import EmergencyPage from './components/EmergencyPage';
import ResultPage from './components/ResultPage';
import UnsentLetter from './components/UnsentLetter';
import BystanderPage from './components/BystanderPage';
import FollowUpPulse from './components/FollowUpPulse';
import ResourcesPage from './components/ResourcesPage';
import AdminLogin from './components/AdminLogin';
import HeatmapDashboard from './components/HeatmapDashboard';
import CaseManagement from './components/CaseManagement';

function App() {
  const [language, setLanguage] = useState('en');
  const [selectedState, setSelectedState] = useState('');
  const [sessionId, setSessionId] = useState('');
  const [safeWord, setSafeWord] = useState('');
  const [caseData, setCaseData] = useState(null);

  return (
    <Router>
      <div className="app">
        <Routes>
          {/* Student Portal Routes */}
          <Route path="/" element={
            <WelcomeScreen 
              language={language}
              onLanguageChange={setLanguage}
              state={selectedState}
              onStateChange={setSelectedState}
            />
          } />
          <Route path="/safe-word" element={
            <SafeWordSetup 
              language={language}
              onComplete={setSafeWord}
            />
          } />
          <Route path="/chat" element={
            <ChatInterface 
              language={language}
              onLanguageChange={setLanguage}
              state={selectedState}
              safeWord={safeWord}
              sessionId={sessionId}
              setSessionId={setSessionId}
              setCaseData={setCaseData}
            />
          } />
          <Route path="/emergency" element={
            <EmergencyPage 
              language={language}
              state={selectedState}
            />
          } />
          <Route path="/result" element={
            <ResultPage 
              language={language}
              state={selectedState}
              caseData={caseData}
            />
          } />
          <Route path="/unsent-letter" element={
            <UnsentLetter 
              language={language}
            />
          } />
          <Route path="/bystander" element={
            <BystanderPage 
              language={language}
              state={selectedState}
            />
          } />
          <Route path="/follow-up" element={
            <FollowUpPulse 
              language={language}
              sessionId={sessionId}
            />
          } />
          <Route path="/resources" element={
            <ResourcesPage 
              language={language}
            />
          } />

          {/* Admin Portal Routes */}
          <Route path="/admin" element={<AdminLogin language={language} />} />
          <Route path="/admin/dashboard" element={<HeatmapDashboard language={language} />} />
          <Route path="/admin/cases" element={<CaseManagement language={language} />} />

          {/* Fallback */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
